(function () {
  window.DENO_DOC_SEARCH_INDEX = {"kind":"search","nodes":[{"id":"namespace_cidrv4fromcidrv64mapped","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4FromCidrv64Mapped","file":"4to6.ts","doc":"Converts an IPv4-mapped IPv6 CIDR block to its IPv4 CIDR representation.The IPv4 address is extracted from the ::ffff:0:0/96 prefix and the prefix length is reduced by 96: an IPv6 /104 becomes an IPv4 /8.","url":"./4to6.ts/~/cidrv4FromCidrv64Mapped.html","deprecated":false},{"id":"namespace_cidrv4tocidrv64mapped","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4ToCidrv64Mapped","file":"4to6.ts","doc":"Converts an IPv4 CIDR block to its IPv4-mapped IPv6 CIDR representation.The address is embedded into the ::ffff:0:0/96 prefix and the prefix length is offset by 96: an IPv4 /8 becomes an IPv6 /104.","url":"./4to6.ts/~/cidrv4ToCidrv64Mapped.html","deprecated":false},{"id":"namespace_ipv4from64mapped","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"ipv4From64Mapped","file":"4to6.ts","doc":"Extracts the IPv4 address from an IPv4-mapped IPv6 address.Takes a 128-bit IPv4-mapped IPv6 address (::ffff:x.x.x.x) and returns the embedded 32-bit IPv4 address as defined in RFC 4291 Section 2.5.5.2.","url":"./4to6.ts/~/ipv4From64Mapped.html","deprecated":false},{"id":"namespace_ipv4to64mapped","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"ipv4To64Mapped","file":"4to6.ts","doc":"Converts an IPv4 address to its IPv4-mapped IPv6 representation.Embeds the 32-bit IPv4 address into the ::ffff:0:0/96 prefix, producing the 128-bit IPv4-mapped IPv6 address defined in RFC 4291 Section 2.5.5.2.","url":"./4to6.ts/~/ipv4To64Mapped.html","deprecated":false},{"id":"namespace_cidraddresses","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrAddresses","file":"cidr.ts","doc":"Generates all addresses in an IPv4 CIDR block.","url":"./cidr.ts/~/cidrAddresses.html","deprecated":false},{"id":"namespace_cidrcontainscidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrContainsCidr","file":"cidr.ts","doc":"Checks if one IPv4 CIDR block fully contains another.","url":"./cidr.ts/~/cidrContainsCidr.html","deprecated":false},{"id":"namespace_cidrintersect","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrIntersect","file":"cidr.ts","doc":"Returns the intersection of two IPv4 CIDR blocks.","url":"./cidr.ts/~/cidrIntersect.html","deprecated":false},{"id":"namespace_cidrmerge","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrMerge","file":"cidr.ts","doc":"Merges IPv4 CIDR blocks into the minimal covering set.","url":"./cidr.ts/~/cidrMerge.html","deprecated":false},{"id":"namespace_cidroverlaps","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrOverlaps","file":"cidr.ts","doc":"Checks if two IPv4 CIDR blocks overlap.","url":"./cidr.ts/~/cidrOverlaps.html","deprecated":false},{"id":"namespace_cidrsize","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrSize","file":"cidr.ts","doc":"Returns the total number of addresses in an IPv4 CIDR block.","url":"./cidr.ts/~/cidrSize.html","deprecated":false},{"id":"namespace_cidrsubtract","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrSubtract","file":"cidr.ts","doc":"Subtracts one IPv4 CIDR block from another.","url":"./cidr.ts/~/cidrSubtract.html","deprecated":false},{"id":"namespace_parsecidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseCidr","file":"cidr.ts","doc":"Parses an IPv4 or IPv6 CIDR notation string.Detects the IP version by checking for : in the input — if present, the CIDR is parsed as IPv6 (returning Cidrv6), otherwise as IPv4 (returning Cidrv4).","url":"./cidr.ts/~/parseCidr.html","deprecated":false},{"id":"namespace_stringifycidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyCidr","file":"cidr.ts","doc":"Stringifies a Cidrv4 to IPv4 CIDR notation.","url":"./cidr.ts/~/stringifyCidr.html","deprecated":false},{"id":"namespace_cidrv4","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"Cidrv4","file":"cidrv4.ts","doc":"Represents an IPv4 CIDR block.Contains only the parsed values from the CIDR notation.","url":"./cidrv4.ts/~/Cidrv4.html","deprecated":false},{"id":"namespace_cidrv4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidrv4.address","file":"cidrv4.ts","doc":"The IPv4 address from the CIDR notation","url":"./cidrv4.ts/~/Cidrv4.address.html","deprecated":false},{"id":"namespace_cidrv4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidrv4.prefixLength","file":"cidrv4.ts","doc":"The prefix length (0-32)","url":"./cidrv4.ts/~/Cidrv4.prefixLength.html","deprecated":false},{"id":"namespace_cidrv4addresses","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Addresses","file":"cidrv4.ts","doc":"","url":"./cidrv4.ts/~/cidrv4Addresses.html","deprecated":false},{"id":"namespace_cidrv4broadcastaddress","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"cidrv4BroadcastAddress","file":"cidrv4.ts","doc":"Returns the broadcast address (last IP) of a CIDR block.Alias for cidrv4LastAddress.","url":"./cidrv4.ts/~/cidrv4BroadcastAddress.html","deprecated":false},{"id":"namespace_cidrv4contains","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Contains","file":"cidrv4.ts","doc":"Checks if an IPv4 address is contained within a CIDR block.","url":"./cidrv4.ts/~/cidrv4Contains.html","deprecated":false},{"id":"namespace_cidrv4containscidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4ContainsCidr","file":"cidrv4.ts","doc":"Checks if one IPv4 CIDR block fully contains another.Returns true when every address in inner is also in outer. This is the case when outer has a shorter-or-equal prefix and both network addresses agree under the outer mask.","url":"./cidrv4.ts/~/cidrv4ContainsCidr.html","deprecated":false},{"id":"namespace_cidrv4firstaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4FirstAddress","file":"cidrv4.ts","doc":"Returns the first address of a CIDR block (network address).","url":"./cidrv4.ts/~/cidrv4FirstAddress.html","deprecated":false},{"id":"namespace_cidrv4intersect","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Intersect","file":"cidrv4.ts","doc":"Returns the intersection of two IPv4 CIDR blocks.Since CIDR blocks are power-of-2-aligned, two overlapping blocks always have a containment relationship -- the intersection is the more specific (longer prefix) block with its canonical network address.","url":"./cidrv4.ts/~/cidrv4Intersect.html","deprecated":false},{"id":"namespace_cidrv4lastaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4LastAddress","file":"cidrv4.ts","doc":"Returns the last address of a CIDR block (broadcast address for IPv4).","url":"./cidrv4.ts/~/cidrv4LastAddress.html","deprecated":false},{"id":"namespace_cidrv4mask","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Mask","file":"cidrv4.ts","doc":"Creates a network mask from an IPv4 prefix length.The prefix length must be between 0 and 32 (inclusive).","url":"./cidrv4.ts/~/cidrv4Mask.html","deprecated":false},{"id":"namespace_cidrv4merge","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Merge","file":"cidrv4.ts","doc":"Merges IPv4 CIDR blocks into the minimal covering set.Takes an array of possibly overlapping, adjacent, or redundant CIDR blocks and returns the minimal set of non-overlapping CIDR prefix blocks covering the exact same address space.","url":"./cidrv4.ts/~/cidrv4Merge.html","deprecated":false},{"id":"namespace_cidrv4networkaddress","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"cidrv4NetworkAddress","file":"cidrv4.ts","doc":"Returns the network address (first IP) of a CIDR block.Alias for cidrv4FirstAddress.","url":"./cidrv4.ts/~/cidrv4NetworkAddress.html","deprecated":false},{"id":"namespace_cidrv4overlaps","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Overlaps","file":"cidrv4.ts","doc":"Checks if two IPv4 CIDR blocks overlap (share at least one address).Two CIDRs overlap when one contains at least one address of the other. This is equivalent to checking containment using the shorter prefix. The check is symmetric: cidrv4Overlaps(a, b) === cidrv4Overlaps(b, a).","url":"./cidrv4.ts/~/cidrv4Overlaps.html","deprecated":false},{"id":"namespace_cidrv4size","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Size","file":"cidrv4.ts","doc":"Returns the total number of IP addresses in a CIDR block or for a given prefix length.For a /24 network, this returns 256. For a /32, this returns 1.","url":"./cidrv4.ts/~/cidrv4Size.html","deprecated":false},{"id":"namespace_cidrv4subtract","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv4Subtract","file":"cidrv4.ts","doc":"Subtracts one IPv4 CIDR block from another.Returns the minimal set of CIDR blocks representing all IP addresses in a but not in b. The algorithm recursively splits a into two halves at prefix+1, keeping the non-overlapping half and recursing into the overlapping half.","url":"./cidrv4.ts/~/cidrv4Subtract.html","deprecated":false},{"id":"namespace_parsecidrv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseCidrv4","file":"cidrv4.ts","doc":"Parses an IPv4 CIDR notation string to a Cidrv4 object.Returns only the parsed values (address and prefix length).","url":"./cidrv4.ts/~/parseCidrv4.html","deprecated":false},{"id":"namespace_stringifycidrv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyCidrv4","file":"cidrv4.ts","doc":"Stringifies a Cidrv4 object to CIDR notation.","url":"./cidrv4.ts/~/stringifyCidrv4.html","deprecated":false},{"id":"namespace_cidrv6","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"Cidrv6","file":"cidrv6.ts","doc":"Represents an IPv6 CIDR block.Contains only the parsed values from the CIDR notation.","url":"./cidrv6.ts/~/Cidrv6.html","deprecated":false},{"id":"namespace_cidrv6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidrv6.address","file":"cidrv6.ts","doc":"The IPv6 address from the CIDR notation","url":"./cidrv6.ts/~/Cidrv6.address.html","deprecated":false},{"id":"namespace_cidrv6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidrv6.prefixLength","file":"cidrv6.ts","doc":"The prefix length (0-128)","url":"./cidrv6.ts/~/Cidrv6.prefixLength.html","deprecated":false},{"id":"namespace_cidrv6addresses","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Addresses","file":"cidrv6.ts","doc":"","url":"./cidrv6.ts/~/cidrv6Addresses.html","deprecated":false},{"id":"namespace_cidrv6contains","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Contains","file":"cidrv6.ts","doc":"Checks if an IPv6 address (as bigint) is contained within a CIDR block.","url":"./cidrv6.ts/~/cidrv6Contains.html","deprecated":false},{"id":"namespace_cidrv6containscidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6ContainsCidr","file":"cidrv6.ts","doc":"Checks if one IPv6 CIDR block fully contains another.Returns true when every address in inner is also in outer. This is the case when outer has a shorter-or-equal prefix and both network addresses agree under the outer mask.","url":"./cidrv6.ts/~/cidrv6ContainsCidr.html","deprecated":false},{"id":"namespace_cidrv6firstaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6FirstAddress","file":"cidrv6.ts","doc":"Returns the first address of a CIDR block.","url":"./cidrv6.ts/~/cidrv6FirstAddress.html","deprecated":false},{"id":"namespace_cidrv6intersect","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Intersect","file":"cidrv6.ts","doc":"Returns the intersection of two IPv6 CIDR blocks.Since CIDR blocks are power-of-2-aligned, two overlapping blocks always have a containment relationship -- the intersection is the more specific (longer prefix) block with its canonical network address.","url":"./cidrv6.ts/~/cidrv6Intersect.html","deprecated":false},{"id":"namespace_cidrv6lastaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6LastAddress","file":"cidrv6.ts","doc":"Returns the last address of a CIDR block.","url":"./cidrv6.ts/~/cidrv6LastAddress.html","deprecated":false},{"id":"namespace_cidrv6mask","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Mask","file":"cidrv6.ts","doc":"Creates a network mask from an IPv6 prefix length.The prefix length must be between 0 and 128 (inclusive).","url":"./cidrv6.ts/~/cidrv6Mask.html","deprecated":false},{"id":"namespace_cidrv6merge","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Merge","file":"cidrv6.ts","doc":"Merges IPv6 CIDR blocks into the minimal covering set.Takes an array of possibly overlapping, adjacent, or redundant CIDR blocks and returns the minimal set of non-overlapping CIDR prefix blocks covering the exact same address space.","url":"./cidrv6.ts/~/cidrv6Merge.html","deprecated":false},{"id":"namespace_cidrv6overlaps","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Overlaps","file":"cidrv6.ts","doc":"Checks if two IPv6 CIDR blocks overlap (share at least one address).Two CIDRs overlap when one contains at least one address of the other. This is equivalent to checking containment using the shorter prefix. The check is symmetric: cidrv6Overlaps(a, b) === cidrv6Overlaps(b, a).","url":"./cidrv6.ts/~/cidrv6Overlaps.html","deprecated":false},{"id":"namespace_cidrv6size","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Size","file":"cidrv6.ts","doc":"Returns the total number of IP addresses in a CIDR block or for a given prefix length.For a /120 network, this returns 256n. For a /128, this returns 1n.Warning: IPv6 subnets can be enormous. A /64 has 2^64 addresses. The result is a bigint to handle these large values.","url":"./cidrv6.ts/~/cidrv6Size.html","deprecated":false},{"id":"namespace_cidrv6subtract","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidrv6Subtract","file":"cidrv6.ts","doc":"Subtracts one IPv6 CIDR block from another.Returns the minimal set of CIDR blocks representing all IP addresses in a but not in b. The algorithm recursively splits a into two halves at prefix+1, keeping the non-overlapping half and recursing into the overlapping half.","url":"./cidrv6.ts/~/cidrv6Subtract.html","deprecated":false},{"id":"namespace_parsecidrv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseCidrv6","file":"cidrv6.ts","doc":"Parses an IPv6 CIDR notation string to a Cidrv6 object.Returns only the parsed values (address and prefix length).","url":"./cidrv6.ts/~/parseCidrv6.html","deprecated":false},{"id":"namespace_stringifycidrv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyCidrv6","file":"cidrv6.ts","doc":"Stringifies a Cidrv6 object to CIDR notation.","url":"./cidrv6.ts/~/stringifyCidrv6.html","deprecated":false},{"id":"namespace_classifiedip","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ClassifiedIp","file":"classify.ts","doc":"Result of classifying an IP address with version information and parsed value.Discriminated union on kind:\"ipv4\" — see ClassifiedIpv4\"ipv6\" — see ClassifiedIpv6","url":"./classify.ts/~/ClassifiedIp.html","deprecated":false},{"id":"namespace_classifiedipv4","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ClassifiedIpv4","file":"classify.ts","doc":"Result of classifying an IPv4 address.Contains the parsed value, the kind discriminant \"ipv4\", and the classification label from ClassificationIpv4.","url":"./classify.ts/~/ClassifiedIpv4.html","deprecated":false},{"id":"namespace_classifiedipv4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv4.kind","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv4.kind.html","deprecated":false},{"id":"namespace_classifiedipv4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv4.value","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv4.value.html","deprecated":false},{"id":"namespace_classifiedipv4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv4.classification","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv4.classification.html","deprecated":false},{"id":"namespace_classifiedipv6","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ClassifiedIpv6","file":"classify.ts","doc":"Result of classifying an IPv6 address.Contains the parsed value, the kind discriminant \"ipv6\", and the classification label from ClassificationIpv6.","url":"./classify.ts/~/ClassifiedIpv6.html","deprecated":false},{"id":"namespace_classifiedipv6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv6.kind","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv6.kind.html","deprecated":false},{"id":"namespace_classifiedipv6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv6.value","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv6.value.html","deprecated":false},{"id":"namespace_classifiedipv6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"ClassifiedIpv6.classification","file":"classify.ts","doc":"","url":"./classify.ts/~/ClassifiedIpv6.classification.html","deprecated":false},{"id":"namespace_classifyip","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"classifyIp","file":"classify.ts","doc":"Classifies an IPv4 address into its well-known range.","url":"./classify.ts/~/classifyIp.html","deprecated":false},{"id":"namespace_classificationipv4","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ClassificationIpv4","file":"classifyv4.ts","doc":"All possible IPv4 address classification labels.Returned by classifyIpv4 to identify which well-known range an IPv4 address belongs to.","url":"./classifyv4.ts/~/ClassificationIpv4.html","deprecated":false},{"id":"namespace_classifyipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"classifyIpv4","file":"classifyv4.ts","doc":"Classifies an IPv4 address into its well-known range.Returns the most specific classification label for the given address. Every valid 32-bit unsigned integer maps to exactly one classification.","url":"./classifyv4.ts/~/classifyIpv4.html","deprecated":false},{"id":"namespace_isipv4benchmarking","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Benchmarking","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in the benchmarking range (RFC 2544).Benchmarking range: 198.18.0.0/15 (198.18.0.0 – 198.19.255.255)","url":"./classifyv4.ts/~/isIpv4Benchmarking.html","deprecated":false},{"id":"namespace_isipv4broadcast","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Broadcast","file":"classifyv4.ts","doc":"Checks if an IPv4 address is the limited broadcast address.Broadcast address: 255.255.255.255","url":"./classifyv4.ts/~/isIpv4Broadcast.html","deprecated":false},{"id":"namespace_isipv4cgnat","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4CgNat","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in the Carrier-Grade NAT range (RFC 6598).CG-NAT range: 100.64.0.0/10 (100.64.0.0 – 100.127.255.255)","url":"./classifyv4.ts/~/isIpv4CgNat.html","deprecated":false},{"id":"namespace_isipv4documentation","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Documentation","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in a documentation range (RFC 5737).Documentation ranges:192.0.2.0/24 (TEST-NET-1)198.51.100.0/24 (TEST-NET-2)203.0.113.0/24 (TEST-NET-3)","url":"./classifyv4.ts/~/isIpv4Documentation.html","deprecated":false},{"id":"namespace_isipv4linklocal","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4LinkLocal","file":"classifyv4.ts","doc":"Checks if an IPv4 address is a link-local address (RFC 3927).Link-local range: 169.254.0.0/16 (169.254.0.0 – 169.254.255.255)","url":"./classifyv4.ts/~/isIpv4LinkLocal.html","deprecated":false},{"id":"namespace_isipv4loopback","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Loopback","file":"classifyv4.ts","doc":"Checks if an IPv4 address is a loopback address (RFC 1122).Loopback range: 127.0.0.0/8 (127.0.0.0 – 127.255.255.255)","url":"./classifyv4.ts/~/isIpv4Loopback.html","deprecated":false},{"id":"namespace_isipv4multicast","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Multicast","file":"classifyv4.ts","doc":"Checks if an IPv4 address is a multicast address (RFC 5771).Multicast range: 224.0.0.0/4 (224.0.0.0 – 239.255.255.255)","url":"./classifyv4.ts/~/isIpv4Multicast.html","deprecated":false},{"id":"namespace_isipv4private","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Private","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in a private range (RFC 1918).Private ranges:10.0.0.0/8 (10.0.0.0 – 10.255.255.255)172.16.0.0/12 (172.16.0.0 – 172.31.255.255)192.168.0.0/16 (192.168.0.0 – 192.168.255.255)","url":"./classifyv4.ts/~/isIpv4Private.html","deprecated":false},{"id":"namespace_isipv4public","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Public","file":"classifyv4.ts","doc":"Checks if an IPv4 address is a public (globally routable) address.Returns true if the address does not belong to any well-known special-purpose range (private, loopback, link-local, multicast, reserved, broadcast, this-network, CG-NAT, benchmarking, or documentation).","url":"./classifyv4.ts/~/isIpv4Public.html","deprecated":false},{"id":"namespace_isipv4reserved","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4Reserved","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in the reserved range (RFC 1112).Reserved range: 240.0.0.0/4 (240.0.0.0 – 255.255.255.254), excluding the broadcast address 255.255.255.255.","url":"./classifyv4.ts/~/isIpv4Reserved.html","deprecated":false},{"id":"namespace_isipv4thisnetwork","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv4ThisNetwork","file":"classifyv4.ts","doc":"Checks if an IPv4 address is in the \"this network\" range (RFC 791).This network range: 0.0.0.0/8 (0.0.0.0 – 0.255.255.255)","url":"./classifyv4.ts/~/isIpv4ThisNetwork.html","deprecated":false},{"id":"namespace_classificationipv6","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ClassificationIpv6","file":"classifyv6.ts","doc":"All possible IPv6 address classification labels.Returned by classifyIpv6 to identify which well-known range an IPv6 address belongs to.","url":"./classifyv6.ts/~/ClassificationIpv6.html","deprecated":false},{"id":"namespace_classifyipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"classifyIpv6","file":"classifyv6.ts","doc":"Classifies an IPv6 address into its well-known range.Returns the most specific classification label for the given address. For overlapping ranges (e.g., 2001:db8::/32 within 2001::/32 within 2000::/3), the most specific match is returned.","url":"./classifyv6.ts/~/classifyIpv6.html","deprecated":false},{"id":"namespace_isipv6benchmarking","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Benchmarking","file":"classifyv6.ts","doc":"Checks if an IPv6 address is in the benchmarking range (RFC 5180).Benchmarking range: 2001:2::/48","url":"./classifyv6.ts/~/isIpv6Benchmarking.html","deprecated":false},{"id":"namespace_isipv6documentation","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Documentation","file":"classifyv6.ts","doc":"Checks if an IPv6 address is in the documentation range (RFC 3849).Documentation range: 2001:db8::/32","url":"./classifyv6.ts/~/isIpv6Documentation.html","deprecated":false},{"id":"namespace_isipv6globalunicast","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6GlobalUnicast","file":"classifyv6.ts","doc":"Checks if an IPv6 address is a global unicast address (RFC 4291).Global unicast range: 2000::/3 (2000:: – 3fff:ffff:...:ffff)Note: This includes sub-ranges like documentation (2001:db8::/32), Teredo (2001::/32), and benchmarking (2001:2::/48). Use the more specific classifiers or classifyIpv6 to distinguish them.","url":"./classifyv6.ts/~/isIpv6GlobalUnicast.html","deprecated":false},{"id":"namespace_isipv6ipv4mapped","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Ipv4Mapped","file":"classifyv6.ts","doc":"Checks if an IPv6 address is an IPv4-mapped address (RFC 4291).IPv4-mapped range: ::ffff:0:0/96 (::ffff:0.0.0.0 – ::ffff:255.255.255.255)","url":"./classifyv6.ts/~/isIpv6Ipv4Mapped.html","deprecated":false},{"id":"namespace_isipv6ipv4translated","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Ipv4Translated","file":"classifyv6.ts","doc":"Checks if an IPv6 address is an IPv4-translated address (RFC 6052).IPv4-translated range: 64:ff9b::/96Used by NAT64 for IPv4/IPv6 translation.","url":"./classifyv6.ts/~/isIpv6Ipv4Translated.html","deprecated":false},{"id":"namespace_isipv6linklocal","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6LinkLocal","file":"classifyv6.ts","doc":"Checks if an IPv6 address is a link-local address (RFC 4291).Link-local range: fe80::/10 (fe80:: – febf:ffff:...:ffff)","url":"./classifyv6.ts/~/isIpv6LinkLocal.html","deprecated":false},{"id":"namespace_isipv6loopback","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Loopback","file":"classifyv6.ts","doc":"Checks if an IPv6 address is the loopback address (RFC 4291).Loopback: ::1","url":"./classifyv6.ts/~/isIpv6Loopback.html","deprecated":false},{"id":"namespace_isipv6multicast","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Multicast","file":"classifyv6.ts","doc":"Checks if an IPv6 address is a multicast address (RFC 4291).Multicast range: ff00::/8 (ff00:: – ffff:ffff:...:ffff)","url":"./classifyv6.ts/~/isIpv6Multicast.html","deprecated":false},{"id":"namespace_isipv6orchidv2","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Orchidv2","file":"classifyv6.ts","doc":"Checks if an IPv6 address is an ORCHIDv2 address (RFC 7343).ORCHIDv2 range: 2001:20::/28","url":"./classifyv6.ts/~/isIpv6Orchidv2.html","deprecated":false},{"id":"namespace_isipv6teredo","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Teredo","file":"classifyv6.ts","doc":"Checks if an IPv6 address is a Teredo address (RFC 4380).Teredo range: 2001::/32Note: This overlaps with documentation (2001:db8::/32), benchmarking (2001:2::/48), and ORCHIDv2 (2001:20::/28) ranges. Use classifyIpv6 for the most specific classification.","url":"./classifyv6.ts/~/isIpv6Teredo.html","deprecated":false},{"id":"namespace_isipv6uniquelocal","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6UniqueLocal","file":"classifyv6.ts","doc":"Checks if an IPv6 address is a unique local address (RFC 4193).Unique local range: fc00::/7 (fc00:: – fdff:ffff:...:ffff)This is the IPv6 equivalent of IPv4 private addresses (RFC 1918).","url":"./classifyv6.ts/~/isIpv6UniqueLocal.html","deprecated":false},{"id":"namespace_isipv6unspecified","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isIpv6Unspecified","file":"classifyv6.ts","doc":"Checks if an IPv6 address is the unspecified address (RFC 4291).Unspecified: ::","url":"./classifyv6.ts/~/isIpv6Unspecified.html","deprecated":false},{"id":"namespace_parseip","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseIp","file":"ip.ts","doc":"Parses an IPv4 or IPv6 address string to its numeric representation.Detects the IP version by checking for : in the input — if present, the address is parsed as IPv6 (returning bigint), otherwise as IPv4 (returning number). IPv4-mapped IPv6 addresses (::ffff:x.x.x.x) are automatically unwrapped to their IPv4 number representation.To preserve the full IPv6 bigint for mapped addresses, use parseIpv6 directly instead.","url":"./ip.ts/~/parseIp.html","deprecated":false},{"id":"namespace_stringifyip","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyIp","file":"ip.ts","doc":"Stringifies an IPv4 (number) or IPv6 (bigint) address to its standard notation.IPv4 addresses (numbers) are always stringified as dotted decimal. Since parseIp unwraps IPv4-mapped IPv6 addresses to numbers, round-tripping a mapped address through parseIp/stringifyIp produces the IPv4 form (e.g. \"192.168.1.1\", not \"::ffff:c0a8:101\").To produce the mapped IPv6 representation, use ipv4To64Mapped with stringifyIpv6:","url":"./ip.ts/~/stringifyIp.html","deprecated":false},{"id":"namespace_parseipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseIpv4","file":"ipv4.ts","doc":"Parses an IPv4 address in dotted decimal notation to a number.The function validates the format and range of each octet. Leading zeros are not allowed (except for \"0\" itself).","url":"./ipv4.ts/~/parseIpv4.html","deprecated":false},{"id":"namespace_stringifyipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyIpv4","file":"ipv4.ts","doc":"Stringifies a number to an IPv4 address in dotted decimal notation.The number must represent a valid 32-bit unsigned integer (0 to 4294967295).","url":"./ipv4.ts/~/stringifyIpv4.html","deprecated":false},{"id":"namespace_compressipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"compressIpv6","file":"ipv6.ts","doc":"Compresses an IPv6 address to its shortest canonical form.This is equivalent to parsing and re-stringifying the address, which produces the canonical compressed representation.","url":"./ipv6.ts/~/compressIpv6.html","deprecated":false},{"id":"namespace_expandipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"expandIpv6","file":"ipv6.ts","doc":"Expands an IPv6 address to its full uncompressed form.Returns the address with all 8 groups fully specified with 4 hex digits each.","url":"./ipv6.ts/~/expandIpv6.html","deprecated":false},{"id":"namespace_parseipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseIpv6","file":"ipv6.ts","doc":"Parses an IPv6 address in colon-hexadecimal notation to a bigint.Supports standard IPv6 formats:Full form: 2001:0db8:0000:0000:0000:0000:0000:0001Compressed form with ::: 2001:db8::1Mixed IPv4 form: ::ffff:192.168.1.1Zone IDs are stripped: fe80::1%eth0 becomes fe80::1","url":"./ipv6.ts/~/parseIpv6.html","deprecated":false},{"id":"namespace_stringifyipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyIpv6","file":"ipv6.ts","doc":"Stringifies a bigint to an IPv6 address in compressed colon-hexadecimal notation.The output uses the canonical compressed form:Leading zeros in each group are omittedThe longest run of consecutive all-zero groups is replaced with ::If there are multiple runs of the same length, the first one is compressed","url":"./ipv6.ts/~/stringifyIpv6.html","deprecated":false},{"id":"namespace_parse","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parse","file":"mod.ts","doc":"Parses an IP address or CIDR notation string.Detects CIDR notation by checking for / in the input. If present, delegates to parseCidr; otherwise delegates to parseIp. The IP version (IPv4 vs IPv6) is auto-detected within each delegate.","url":"./mod.ts/~/parse.html","deprecated":false},{"id":"namespace_stringify","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringify","file":"mod.ts","doc":"Stringifies an IPv4 address (number) to dotted decimal notation.","url":"./mod.ts/~/stringify.html","deprecated":false},{"id":"namespace_isvalidcidr","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidCidr","file":"validate.ts","doc":"Checks if a string is valid IPv4 or IPv6 CIDR notation.","url":"./validate.ts/~/isValidCidr.html","deprecated":false},{"id":"namespace_isvalidip","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidIp","file":"validate.ts","doc":"Checks if a string is a valid plain IP address (IPv4 or IPv6).Does not accept CIDR notation — use isValidCidr for that.","url":"./validate.ts/~/isValidIp.html","deprecated":false},{"id":"namespace_isvalidcidrv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidCidrv4","file":"validatev4.ts","doc":"Checks if a string is valid IPv4 CIDR notation.","url":"./validatev4.ts/~/isValidCidrv4.html","deprecated":false},{"id":"namespace_isvalidipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidIpv4","file":"validatev4.ts","doc":"Checks if a string is a valid IPv4 address in dotted decimal notation.","url":"./validatev4.ts/~/isValidIpv4.html","deprecated":false},{"id":"namespace_isvalidcidrv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidCidrv6","file":"validatev6.ts","doc":"Checks if a string is valid IPv6 CIDR notation.","url":"./validatev6.ts/~/isValidCidrv6.html","deprecated":false},{"id":"namespace_isvalidipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidIpv6","file":"validatev6.ts","doc":"Checks if a string is a valid IPv6 address in colon-hexadecimal notation.Accepts full form, compressed form with ::, IPv4-mapped addresses (::ffff:192.168.1.1), and addresses with zone IDs (fe80::1%eth0).","url":"./validatev6.ts/~/isValidIpv6.html","deprecated":false}]};
})()